    <input type="checkbox" id="checkbox1" value="option1"> Option 1<br>
    <input type="checkbox" id="checkbox2" value="option2"> Option 2<br>
    <input type="checkbox" id="checkbox3" value="option3"> Option 3<br>

    <!-- Save button -->
    <button id="saveButton">Save</button>

    <script>
        // Function to select all checkboxes
        function selectAllCheckboxes() {
            // Select all checkboxes
            const checkboxes = document.querySelectorAll('input[type="checkbox"]');

            // Loop through each checkbox and check it
            checkboxes.forEach(checkbox => {
                checkbox.checked = true;
            });
